templates.stackfile:
services:
  {{APP_NAME}}:
    image: lscr.io/linuxserver/openssh-server:latest
    container_name: {{APP_NAME}}
    restart: unless-stopped
    environment:
      TZ: {{APP_TZ}}
      PUBLIC_KEY: {{PUBLIC_KEY}}
      PUBLIC_KEY_FILE: {{PUBLIC_KEY_FILE}}
      PUBLIC_KEY_DIR: {{PUBLIC_KEY_DIR}}
      PUBLIC_KEY_URL: {{PUBLIC_KEY_URL}}
      SUDO_ACCESS: {{SUDO_ACCESS}}
      PASSWORD_ACCESS: {{PASSWORD_ACCESS}}
      USER_PASSWORD: {{USER_PASSWORD}}
      USER_PASSWORD_FILE: {{USER_PASSWORD_FILE}}
      USER_NAME: {{USER_NAME}}
      LOG_STDOUT: {{LOG_STDOUT}}
    volumes:
      - {{APP_NAME}}_config:/config
    networks:
      - proxy
    labels:
      - traefik.enable=true
      - traefik.docker.network=proxy
      - traefik.http.routers.{{APP_NAME}}.rule=Host(`{{APP_SUBDOMAIN}}.{{APP_DOMAIN}}`)
      - traefik.http.routers.{{APP_NAME}}.entrypoints=web
      - traefik.http.services.{{APP_NAME}}.loadbalancer.server.port=2222

volumes:
  {{APP_NAME}}_config:

networks:
  proxy:
    external: true
